PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE `analytics` (
	`id` text PRIMARY KEY NOT NULL,
	`project_id` text NOT NULL,
	`tour_id` text,
	`user_id` text,
	`step_index` integer NOT NULL,
	`event_type` text NOT NULL,
	`timestamp` integer NOT NULL,
	FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`tour_id`) REFERENCES `tours`(`id`) ON UPDATE no action ON DELETE set null
);
CREATE TABLE `projects` (
	`id` text PRIMARY KEY NOT NULL,
	`name` text NOT NULL,
	`api_key` text NOT NULL,
	`allowed_origins` text NOT NULL,
	`created_at` integer NOT NULL
);
CREATE TABLE `tours` (
	`id` text PRIMARY KEY NOT NULL,
	`project_id` text NOT NULL,
	`context_key` text NOT NULL,
	`version_hash` text NOT NULL,
	`steps_json` text NOT NULL,
	`element_fingerprints` text,
	`is_active` integer DEFAULT true NOT NULL,
	`created_at` integer NOT NULL,
	`updated_at` integer NOT NULL,
	FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON UPDATE no action ON DELETE cascade
);
CREATE TABLE `user_progress` (
	`id` text PRIMARY KEY NOT NULL,
	`project_id` text NOT NULL,
	`user_id` text NOT NULL,
	`tour_id` text NOT NULL,
	`status` text NOT NULL,
	`completed_at` integer,
	`created_at` integer NOT NULL,
	FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`) ON UPDATE no action ON DELETE cascade,
	FOREIGN KEY (`tour_id`) REFERENCES `tours`(`id`) ON UPDATE no action ON DELETE cascade
);
DELETE FROM sqlite_sequence;
CREATE INDEX `project_time_idx` ON `analytics` (`project_id`,`timestamp`);
CREATE UNIQUE INDEX `projects_api_key_unique` ON `projects` (`api_key`);
CREATE INDEX `api_key_idx` ON `projects` (`api_key`);
CREATE INDEX `context_hash_idx` ON `tours` (`context_key`,`version_hash`);
CREATE INDEX `user_tour_idx` ON `user_progress` (`user_id`,`tour_id`);
CREATE INDEX `project_user_idx` ON `user_progress` (`project_id`,`user_id`);
CREATE UNIQUE INDEX origin_uniq_idx ON projects(allowed_origins);
CREATE INDEX active_context_idx ON tours(project_id, context_key);
